package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that windows trading events into fixed market session windows based on
 * the timestamp of the elements. Each window corresponds to a single trading day's session
 * (e.g., NYSE 09:30-16:00 ET, LSE 08:00-16:30 GMT).
 *
 * <p>Events are assigned to the session window for the trading day that their timestamp falls in.
 * If an event's timestamp is before the session open on a given day, it is grouped with that day's
 * session. If the timestamp is after the session close, it is grouped with the next day's session.
 *
 * <p>Example usage:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * KeyedStream<TradeEvent, String> keyed = trades.keyBy(TradeEvent::getSymbol);
 * WindowedStream<TradeEvent, String, TimeWindow> windowed =
 *   keyed.window(PricingSessionWindow.forMarket(
 *       "NYSE",
 *       ZoneId.of("America/New_York"),
 *       LocalTime.of(9, 30),
 *       LocalTime.of(16, 0)));
 * }</pre>
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    protected PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("marketId must not be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("timezone must not be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException("sessionOpen and sessionClose must not be null");
        }
        if (!sessionOpen.isBefore(sessionClose)) {
            throw new IllegalArgumentException(
                    "sessionOpen must be before sessionClose; for overnight sessions "
                            + "spanning midnight, split into two windows");
        }
        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    /**
     * Creates a new {@code PricingSessionWindow} for the given market.
     *
     * @param marketId A human-readable market identifier (e.g., "NYSE", "LSE").
     * @param timezone The timezone in which the session hours are expressed.
     * @param open The local time at which the session opens (inclusive).
     * @param close The local time at which the session closes (exclusive).
     * @return The configured {@code PricingSessionWindow} assigner.
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime open, LocalTime close) {
        return new PricingSessionWindow(marketId, timezone, open, close);
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert epoch milliseconds to a ZonedDateTime in the market's timezone
        ZonedDateTime eventTime =
                Instant.ofEpochMilli(timestamp).atZone(timezone);

        LocalDate eventDate = eventTime.toLocalDate();
