public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    /**
     * State descriptor used to track whether an early-fire has been requested for this window
     * (e.g., due to a circuit breaker halt signal).
     */
    private static final ValueStateDescriptor<Boolean> EARLY_FIRE_STATE =
            new ValueStateDescriptor<>("pricing-session-early-fire", Types.BOOLEAN);

    private PricingSessionTrigger() {}

    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Check if an early fire has been requested for this window
        ValueState<Boolean> earlyFireState = ctx.getPartitionedState(EARLY_FIRE_STATE);
        Boolean earlyFire = earlyFireState.value();
        if (Boolean.TRUE.equals(earlyFire)) {
            // Clear the early-fire flag and fire immediately
            earlyFireState.clear();
            return TriggerResult.FIRE;
        }

        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
            // Watermark already past the window end: fire immediately
            return TriggerResult.FIRE;
        } else {
            // Register a timer for the market close (window end)
            ctx.registerEventTimeTimer(window.maxTimestamp());
            return TriggerResult.CONTINUE;
        }
    }

    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Fire when the watermark passes the session close time
        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        return TriggerResult.CONTINUE;
    }

    @Override
    public boolean canMerge() {
        return true;
    }

    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
        // Merge the early-fire state from constituent windows into the merged window
        ctx.mergePartitionedState(EARLY_FIRE_STATE);

        // Re-register the timer for the merged window's end (market close)
        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }
    }

    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        // Delete the event-time timer and clean up state
        ctx.deleteEventTimeTimer(window.maxTimestamp());
        ctx.getPartitionedState(EARLY_FIRE_STATE).clear();
    }

    /**
     * Signals that an early fire should occur for the window containing the next element. This can
     * be called externally when a circuit breaker halt or other extraordinary event is detected.
     *
     * @param ctx The trigger context for the current window.
     * @throws Exception if state access fails.
     */
    public void signalEarlyFire(TriggerContext ctx) throws Exception {
        ctx.getPartitionedState(EARLY_FIRE_STATE).update(Boolean.TRUE);
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    /**
     * Creates a new {@code PricingSessionTrigger} that fires at market close (the end of the
     * session window).
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }
}
